import{_ as a,c as e,o as t,a4 as i}from"./chunks/framework.CzjLcc5X.js";const f=JSON.parse('{"title":"日本 -> 山梨 -> 活動 -> 攀登富士山","description":"","frontmatter":{},"headers":[],"relativePath":"日本/山梨/活動/攀登富士山.md","filePath":"日本/山梨/活動/攀登富士山.md","lastUpdated":1690640927000}'),l={name:"日本/山梨/活動/攀登富士山.md"},r=i('<h1 id="攀登富士山" tabindex="-1">攀登富士山 <a class="header-anchor" href="#攀登富士山" aria-label="Permalink to &quot;攀登富士山&quot;">​</a></h1><p>富士山開放登山時間為 7 月上旬至 9 月上旬，旺季是 7 月底到 8 月底。只有在這段期間內才會開放一般民眾登山。通常落在 8 月中旬的盂蘭盆節期間，登山路線的人潮最為擁擠，且可能會因為下大雨或刮強風而關閉，所以請謹慎安排登山時間。</p><h2 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h2><p>東京出發的登山者可從新宿車站搭乘直達吉田路線的五合目巴士，車程約 2 小時 30 分鐘。這條巴士路線僅在登山季才有行駛。</p><h2 id="攀登富士山的-country-code" tabindex="-1">攀登富士山的 Country Code <a class="header-anchor" href="#攀登富士山的-country-code" aria-label="Permalink to &quot;攀登富士山的 Country Code&quot;">​</a></h2><p>在富士山登山道必須遵守的規則與禮儀。</p><ul><li>不要採摘/捕捉富士山上的動植物，以免破壞生態平衡</li><li>不要帶走、移動山上任何石塊</li><li>不要架設任何營帳，山上並沒帶任何露營地點</li><li>不要攜帶寵物登富士山</li><li>帶走登山中途所產生的垃圾</li><li>不要帶即棄用品登山</li><li>不在登山道以外地方行走</li><li>不要破壞/踏上松散的泥土部份，以避免地形損壞</li><li>保持公共設施、洗手間整潔</li></ul><h2 id="相關連結" tabindex="-1">相關連結 <a class="header-anchor" href="#相關連結" aria-label="Permalink to &quot;相關連結&quot;">​</a></h2><ul><li><a href="https://www.japan.travel/tw/fuji-guide/mt-fuji-climbing-guide/" target="_blank" rel="noreferrer">富士山攀登指南</a></li><li><a href="https://livejapan.com/zh-tw/in-tokyo/in-pref-fuji_mountain/in-mount_fuji/article-a0004111/" target="_blank" rel="noreferrer">Live Japan - 爬富士山新手必看！登山時期、必備品、行前訓練、路線、交通全方位指南</a></li></ul>',9),o=[r];function n(_,c,d,s,h,u){return t(),e("div",null,o)}const m=a(l,[["render",n]]);export{f as __pageData,m as default};
